     1→/**
     2→ * Calculator Widget
     3→ *
     4→ * Basic calculator with arithmetic operations and memory functions
     5→ */
     6→
     7→import React, { useState } from 'react';
     8→import { BaseWidget } from './BaseWidget';
     9→
    10→export const CalculatorWidget: React.FC = () => {
    11→  const [display, setDisplay] = useState('0');
    12→  const [previousValue, setPreviousValue] = useState<number | null>(null);
    13→  const [operation, setOperation] = useState<string | null>(null);
    14→  const [newNumber, setNewNumber] = useState(true);
    15→  const [memory, setMemory] = useState(0);
    16→
    17→  const handleNumber = (num: string) => {
    18→    if (newNumber) {
    19→      setDisplay(num);
    20→      setNewNumber(false);
    21→    } else {
    22→      setDisplay(display === '0' ? num : display + num);
    23→    }
    24→  };
    25→
    26→  const handleDecimal = () => {
    27→    if (newNumber) {
    28→      setDisplay('0.');
    29→      setNewNumber(false);
    30→    } else if (!display.includes('.')) {
    31→      setDisplay(display + '.');
    32→    }
    33→  };
    34→
    35→  const handleOperation = (op: string) => {
    36→    const current = parseFloat(display);
    37→
    38→    if (previousValue !== null && operation && !newNumber) {
    39→      // Complete previous operation
    40→      const result = calculate(previousValue, current, operation);
    41→      setDisplay(String(result));
    42→      setPreviousValue(result);
    43→    } else {
    44→      setPreviousValue(current);
    45→    }
    46→
    47→    setOperation(op);
    48→    setNewNumber(true);
    49→  };
    50→
    51→  const calculate = (prev: number, current: number, op: string): number => {
    52→    switch (op) {
    53→      case '+': return prev + current;
    54→      case '-': return prev - current;
    55→      case '×': return prev * current;
    56→      case '÷': return current !== 0 ? prev / current : 0;
    57→      default: return current;
    58→    }
    59→  };
    60→
    61→  const handleEquals = () => {
    62→    if (previousValue !== null && operation) {
    63→      const current = parseFloat(display);
    64→      const result = calculate(previousValue, current, operation);
    65→      setDisplay(String(result));
    66→      setPreviousValue(null);
    67→      setOperation(null);
    68→      setNewNumber(true);
    69→    }
    70→  };
    71→
    72→  const handleClear = () => {
    73→    setDisplay('0');
    74→    setPreviousValue(null);
    75→    setOperation(null);
    76→    setNewNumber(true);
    77→  };
    78→
    79→  const handleBackspace = () => {
    80→    if (display.length > 1) {
    81→      setDisplay(display.slice(0, -1));
    82→    } else {
    83→      setDisplay('0');
    84→      setNewNumber(true);
    85→    }
    86→  };
    87→
    88→  const handleMemoryAdd = () => setMemory(memory + parseFloat(display));
    89→  const handleMemorySubtract = () => setMemory(memory - parseFloat(display));
    90→  const handleMemoryRecall = () => {
    91→    setDisplay(String(memory));
    92→    setNewNumber(true);
    93→  };
    94→  const handleMemoryClear = () => setMemory(0);
    95→
    96→  const Button: React.FC<{ value: string; onClick: () => void; className?: string; colspan?: boolean }> = ({
    97→    value,
    98→    onClick,
    99→    className = '',
   100→    colspan = false
   101→  }) => (
   102→    <button
   103→      onClick={onClick}
   104→      className={`
   105→        ${colspan ? 'col-span-2' : ''}
   106→        px-3 py-2 rounded-button font-medium
   107→        bg-surface-light-elevated dark:bg-surface-dark-elevated
   108→        hover:bg-neutral-200 dark:hover:bg-neutral-700
   109→        text-text-light-primary dark:text-text-dark-primary
   110→        transition-all duration-standard ease-smooth active:scale-95
   111→        ${className}
   112→      `}
   113→    >
   114→      {value}
   115→    </button>
   116→  );
   117→
   118→  return (
   119→    <BaseWidget title="Calculator" icon="🔢">
   120→      <div className="space-y-3">
   121→        {/* Display */}
   122→        <div className="bg-surface-light dark:bg-surface-dark p-4 rounded-button transition-all duration-standard ease-smooth text-right">
   123→          <div className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary font-mono truncate">
   124→            {display}
   125→          </div>
   126→          {memory !== 0 && (
   127→            <div className="text-xs text-accent-blue mt-1">
   128→              M: {memory}
   129→            </div>
   130→          )}
   131→        </div>
   132→
   133→        {/* Buttons */}
   134→        <div className="grid grid-cols-4 gap-2">
   135→          {/* Row 1: Memory + Clear */}
   136→          <Button value="MC" onClick={handleMemoryClear} className="text-sm" />
   137→          <Button value="MR" onClick={handleMemoryRecall} className="text-sm" />
   138→          <Button value="M+" onClick={handleMemoryAdd} className="text-sm" />
   139→          <Button value="M-" onClick={handleMemorySubtract} className="text-sm" />
   140→
   141→          {/* Row 2: Numbers 7-9 + Divide */}
   142→          <Button value="7" onClick={() => handleNumber('7')} />
   143→          <Button value="8" onClick={() => handleNumber('8')} />
   144→          <Button value="9" onClick={() => handleNumber('9')} />
   145→          <Button value="÷" onClick={() => handleOperation('÷')} className="text-accent-blue font-bold" />
   146→
   147→          {/* Row 3: Numbers 4-6 + Multiply */}
   148→          <Button value="4" onClick={() => handleNumber('4')} />
   149→          <Button value="5" onClick={() => handleNumber('5')} />
   150→          <Button value="6" onClick={() => handleNumber('6')} />
   151→          <Button value="×" onClick={() => handleOperation('×')} className="text-accent-blue font-bold" />
   152→
   153→          {/* Row 4: Numbers 1-3 + Subtract */}
   154→          <Button value="1" onClick={() => handleNumber('1')} />
   155→          <Button value="2" onClick={() => handleNumber('2')} />
   156→          <Button value="3" onClick={() => handleNumber('3')} />
   157→          <Button value="-" onClick={() => handleOperation('-')} className="text-accent-blue font-bold" />
   158→
   159→          {/* Row 5: 0, Decimal, Clear, Add */}
   160→          <Button value="0" onClick={() => handleNumber('0')} />
   161→          <Button value="." onClick={handleDecimal} />
   162→          <Button value="C" onClick={handleClear} className="text-status-error" />
   163→          <Button value="+" onClick={() => handleOperation('+')} className="text-accent-blue font-bold" />
   164→
   165→          {/* Row 6: Backspace + Equals */}
   166→          <Button value="⌫" onClick={handleBackspace} className="text-sm" />
   167→          <Button value="=" onClick={handleEquals} colspan className="bg-accent-blue hover:bg-accent-blue-hover text-white font-bold" />
   168→        </div>
   169→      </div>
   170→    </BaseWidget>
   171→  );
   172→};
