                <div className="p-4 bg-accent-red/10 dark:bg-accent-red/20 border-2 border-accent-red dark:border-accent-red rounded-lg shadow-xl text-sm text-accent-red dark:text-accent-red font-medium">
                  ⚠️ {error}
                </div>
              </div>
            )}

