            {showCityInput ? (
              <div className="absolute top-4 left-4 z-10 flex gap-2 max-w-[280px]">
                <form onSubmit={handleCitySubmit} className="flex gap-2 flex-1 min-w-0">
                  <input
                    type="text"
                    value={cityInput}
                    onChange={(e) => setCityInput(e.target.value)}
                    placeholder="Enter city..."
                    className="flex-1 min-w-0 px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-cyan shadow-lg"
