                  >
                    {loading ? '...' : 'Go'}
                  </button>
                  <button
                    type="button"
                    onClick={() => {
                      setShowCityInput(false);
                      getUserLocation();
                    }}
                    className="px-3 py-2 text-sm bg-surface-light dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary rounded-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark shadow-lg"
                    title="Use my location"
                  >
                    📍
                  </button>
                </form>
              </div>
            ) : (
              <button
                onClick={() => setShowCityInput(true)}
                className="absolute top-4 left-4 z-10 px-3 py-2 text-sm bg-surface-light dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark hover:text-accent-cyan transition-colors rounded-lg shadow-lg border border-border-light dark:border-border-dark"
              >
                📍 {city || 'Set Location'} ✏️
